import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Lq6hU67C.js";const g=JSON.parse('{"title":"ILPP settings (JSON)","description":"","frontmatter":{},"headers":[],"relativePath":"reference/ilpp-settings.md","filePath":"reference/ilpp-settings.md"}'),n={name:"reference/ilpp-settings.md"};function o(l,e,r,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="ilpp-settings-json" tabindex="-1">ILPP settings (JSON) <a class="header-anchor" href="#ilpp-settings-json" aria-label="Permalink to &quot;ILPP settings (JSON)&quot;">​</a></h1><p>During compilation, ILPP reads settings from:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Library/AddressablesLeakDetector/ilpp_settings.json</span></span></code></pre></div><p>EditorPrefs are <strong>not</strong> available in the ILPP pipeline — the Editor writes this file when you change toolbar or settings-menu options.</p><h2 id="typical-fields" tabindex="-1">Typical fields <a class="header-anchor" href="#typical-fields" aria-label="Permalink to &quot;Typical fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Default</th></tr></thead><tbody><tr><td><code>recordingEnabled</code></td><td>Gate all injection</td><td><code>true</code></td></tr><tr><td><code>captureStackTraces</code></td><td>Verbose stack at load/release</td><td><code>false</code></td></tr><tr><td><code>ilppDiagnosticsEnabled</code></td><td>Console injection stats</td><td><code>false</code></td></tr><tr><td><code>excludedAssemblies</code></td><td>Semicolon-separated asm names to skip</td><td>package defaults</td></tr></tbody></table><p>Exact schema may evolve between versions; treat missing keys as documented defaults.</p><h2 id="when-the-file-is-written" tabindex="-1">When the file is written <a class="header-anchor" href="#when-the-file-is-written" aria-label="Permalink to &quot;When the file is written&quot;">​</a></h2><ul><li>Opening the Leak Detector window (initial sync)</li><li>Toggling <strong>Recording</strong> or <strong>Verbose</strong></li><li>Changing assembly exclude list or ILPP diagnostics</li></ul><p>Each change triggers <strong>script recompile</strong> so the next ILPP pass reads updated JSON.</p><h2 id="manual-inspection" tabindex="-1">Manual inspection <a class="header-anchor" href="#manual-inspection" aria-label="Permalink to &quot;Manual inspection&quot;">​</a></h2><p>You can open the JSON in a text editor while Unity is closed or after changing settings. Do not hand-edit while Unity is recompiling.</p><h2 id="paused-recording" tabindex="-1">Paused recording <a class="header-anchor" href="#paused-recording" aria-label="Permalink to &quot;Paused recording&quot;">​</a></h2><p>When <code>recordingEnabled</code> is <code>false</code>, ILPP skips injection — existing compiled assemblies retain prior instrumentation until next full recompile of those assemblies.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics</a></li><li><a href="./../how-to/assembly-exclude-list.html">Assembly exclude list</a></li></ul>',16)])])}const u=t(n,[["render",o]]);export{g as __pageData,u as default};
